STAGE_LABELS = {
    1: 'recall',
    2: 'detail',
    3: 'meaning',
    4: 'synthesis',
    5: 'significance',
}


def wrong_answers(chapter, fact_index):
    chapter_facts = CHAPTERS[chapter]['facts']
    pool = []
    for idx, fact in enumerate(chapter_facts):
        if idx != fact_index:
            pool.append(fact['answer'])
    for other_chapter in (chapter - 1, chapter + 1):
        if other_chapter in CHAPTERS:
            pool.extend(f['answer'] for f in CHAPTERS[other_chapter]['facts'])
    seen = []
    for item in pool:
        if item not in seen:
            seen.append(item)
    return seen


def make_choices(correct, distractors, chapter, fact_index):
    choices = []
    for item in distractors + wrong_answers(chapter, fact_index):
        if item != correct and item not in choices:
            choices.append(item)
        if len(choices) == 3:
            break
    if len(choices) < 3:
        raise ValueError(f'Not enough distractors for chapter {chapter} fact {fact_index + 1}')
    answer_pos = (chapter + fact_index) % 4
    ordered = choices[:]
    ordered.insert(answer_pos, correct)
    return ordered


def build_question(chapter, stage, fact_index, fact):
    topic = CHAPTERS[chapter]['topic']
    base_prompt = fact['prompt']
    if stage == 1:
        prompt = base_prompt
        explanation = f"{fact['meaning']} ({fact['verse']})."
    elif stage == 2:
        prompt = f"According to {BOOK_NAME} {chapter}, which detail fits the {topic} instructions?"
        correct = fact['answer']
        choices = make_choices(correct, fact['distractors'], chapter, fact_index)
        explanation = f"{fact['meaning']} That detail is part of the {topic} instructions in {fact['verse']}."
        return {
            'book_number': BOOK_NUMBER,
            'chapter': chapter,
            'difficulty_stage': stage,
            'prompt': f"{prompt} ({fact['verse']})",
            'choices_json': choices,
            'correct_answer': correct,
            'explanation': explanation,
        }
    elif stage == 3:
        prompt = f"In {BOOK_NAME} {chapter}, what does this detail chiefly emphasize: {fact['answer'].lower()}?"
        correct = fact['theme']
        choices = [
            correct,
            f"That ritual details were optional once the offering began",
            f"That holiness depended mainly on political power",
            f"That the chapter dismisses priestly mediation",
        ]
        answer_pos = (chapter + fact_index + stage) % 4
        wrongs = choices[1:]
        ordered = wrongs[:]
        ordered.insert(answer_pos, correct)
        explanation = f"{fact['theme']} {fact['meaning']} ({fact['verse']})."
        return {
            'book_number': BOOK_NUMBER,
            'chapter': chapter,
            'difficulty_stage': stage,
            'prompt': prompt,
            'choices_json': ordered,
            'correct_answer': correct,
            'explanation': explanation,
        }
    elif stage == 4:
        prompt = f"How does {BOOK_NAME} {chapter} use the detail '{fact['answer']}' within the chapter as a whole?"
        correct = fact['synthesis']
        choices = [
            correct,
            f"It shows the chapter replacing sacrifice with private preference.",
            f"It proves the chapter is mainly about military conquest.",
            f"It minimizes the need for holiness in worship and community life.",
        ]
        answer_pos = (chapter * 2 + fact_index) % 4
        wrongs = choices[1:]
        ordered = wrongs[:]
        ordered.insert(answer_pos, correct)
        explanation = f"{fact['synthesis']} The detail appears in {fact['verse']}."
        return {
            'book_number': BOOK_NUMBER,
            'chapter': chapter,
            'difficulty_stage': stage,
            'prompt': prompt,
            'choices_json': ordered,
            'correct_answer': correct,
            'explanation': explanation,
        }
    else:
        prompt = f"What larger theological point in {BOOK_NAME} {chapter} is reinforced by the detail '{fact['answer']}'?"
        correct = fact['theme']
        choices = [
            correct,
            'That worship can be detached from covenant obedience',
            'That ritual uncleanness has no relation to God\'s dwelling among his people',
            'That Israel\'s life is ordered chiefly by surrounding nations rather than the LORD',
        ]
        answer_pos = (chapter + fact_index + 1) % 4
        wrongs = choices[1:]
        ordered = wrongs[:]
        ordered.insert(answer_pos, correct)
        explanation = f"{fact['theme']} In context, the chapter uses this detail as part of that wider point ({fact['verse']})."
        return {
            'book_number': BOOK_NUMBER,
            'chapter': chapter,
            'difficulty_stage': stage,
            'prompt': prompt,
            'choices_json': ordered,
            'correct_answer': correct,
            'explanation': explanation,
        }

    correct = fact['answer']
    choices = make_choices(correct, fact['distractors'], chapter, fact_index)
    return {
        'book_number': BOOK_NUMBER,
        'chapter': chapter,
        'difficulty_stage': stage,
        'prompt': prompt,
        'choices_json': choices,
        'correct_answer': correct,
        'explanation': explanation,
    }


questions = []
for chapter in range(1, 28):
    facts = CHAPTERS[chapter]['facts']
    if len(facts) != 7:
        raise ValueError(f'Chapter {chapter} does not have 7 facts')
    for stage in range(1, 6):
        for idx, fact in enumerate(facts):
            questions.append(build_question(chapter, stage, idx, fact))

questions.sort(key=lambda item: (item['chapter'], item['difficulty_stage'], item['prompt']))

for item in questions:
    if list(item.keys()) != ['book_number', 'chapter', 'difficulty_stage', 'prompt', 'choices_json', 'correct_answer', 'explanation']:
        raise ValueError('Bad key order')
    if len(item['choices_json']) != 4:
        raise ValueError('Bad choices length')
    if item['correct_answer'] not in item['choices_json']:
        raise ValueError('Correct answer missing from choices')
    for text_key in ('prompt', 'correct_answer', 'explanation'):
        item[text_key].encode('ascii')
    for choice in item['choices_json']:
        choice.encode('ascii')

OUT_PATH.write_text(json.dumps(questions, indent=2) + '\n', encoding='ascii')
print(f'Wrote {len(questions)} questions to {OUT_PATH}')
